public class FileService {

    private static final Logger logger = Logger.getLogger(FileService.class.getName());
    private static final String UPLOAD_BASE_DIR = "/tmp/upload/";

    /**
     * Reads the content of a file and returns it as a string.
     * 
     * @param filePath the path to the file to read
     * @return the complete file content as a string
     * @throws IOException if the file does not exist or cannot be read
     * @throws SecurityException if the file path attempts directory traversal
     */
    public String readFileContent(String filePath) throws IOException {
        if (filePath == null || filePath.trim().isEmpty()) {
            logger.warning("File path is null or empty");
            throw new IOException("File path cannot be null or empty");
        }

        // Normalize the file path to prevent directory traversal attacks
        Path requestedPath = Paths.get(filePath).normalize();
        Path basePath = Paths.get(UPLOAD_BASE_DIR).normalize();
