        if (!Files.isRegularFile(absolutePath)) {
            logger.warning("Path is not a regular file: " + absolutePath);
            throw new IOException("Path is not a regular file: " + filePath);
        }

        // Check if file is readable
        if (!Files.isReadable(absolutePath)) {
            logger.warning("File is not readable: " + absolutePath);
            throw new IOException("File is not readable: " + filePath);
        }

        try {
            // Read all file content using UTF-8 encoding
            logger.info("Reading file: " + absolutePath);
            String content = Files.readString(absolutePath, StandardCharsets.UTF_8);
            logger.info("Successfully read file: " + absolutePath + " (size: " + content.length() + " characters)");
            return content;
