    public String readFileContent(String filePath) throws IOException {
        // Validate input
        if (filePath == null || filePath.trim().isEmpty()) {
            LOGGER.log(Level.WARNING, "File path is null or empty");
            throw new IllegalArgumentException("File path cannot be null or empty");
        }

        LOGGER.log(Level.INFO, "Attempting to read file: {0}", filePath);

        try {
            // Convert to Path object - resolve relative to base path
            Path basePath = Paths.get(ALLOWED_BASE_PATH).normalize().toAbsolutePath();
            Path path = basePath.resolve(filePath).normalize().toAbsolutePath();

            // Security check: Ensure the file is within the allowed directory
            // This prevents path traversal attacks (e.g., ../../etc/passwd)
            if (!path.startsWith(basePath)) {
                LOGGER.log(Level.WARNING, "Attempted to access file outside allowed directory: {0}", path);
                throw new IOException("Access denied: File must be within " + ALLOWED_BASE_PATH + " directory");
            }

            // Check if file exists
            if (!Files.exists(path)) {
                LOGGER.log(Level.WARNING, "File does not exist: {0}", path);
                throw new IOException("File does not exist: " + filePath);
            }

            // Check if it's a regular file (not a directory)
            if (!Files.isRegularFile(path)) {
                LOGGER.log(Level.WARNING, "Path is not a regular file: {0}", path);
                throw new IOException("Path is not a regular file: " + filePath);
            }

            // Check if file is readable
            if (!Files.isReadable(path)) {
                LOGGER.log(Level.WARNING, "File is not readable: {0}", path);
                throw new IOException("File is not readable: " + filePath);
            }

            // Read file content with UTF-8 encoding
            byte[] bytes = Files.readAllBytes(path);
            String content = new String(bytes, StandardCharsets.UTF_8);

            LOGGER.log(Level.INFO, "Successfully read file: {0}, size: {1} bytes", 
                      new Object[]{path, bytes.length});

            return content;

        } catch (IOException e) {
            LOGGER.log(Level.SEVERE, "Failed to read file: " + filePath, e);
            throw e;
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Unexpected error while reading file: " + filePath, e);
            throw new IOException("Failed to read file: " + e.getMessage(), e);
        }
    }
}
